import numpy as np
import random

# Problem constants
PLASTIC_LIMIT = 1200
ELECTRONICS_LIMIT = 800
M = (PLASTIC_LIMIT // min([30, 10, 20, 15]) + ELECTRONICS_LIMIT // min([8, 5, 3, 2]))  # A sufficiently large constant
PROFITS = [15, 8, 12, 5]  # Profits for robots, model cars, building blocks, dolls
PLASTIC_USAGE = [30, 10, 20, 15]  # Plastic required for each type of toy
ELECTRONICS_USAGE = [8, 5, 3, 2]  # Electronics required for each type of toy

# Initialize the solution
def initialize_solution():
    return {
        "x1": 0, "x2": 0, "x3": 0, "x4": 0,  # Number of each toy type
        "y1": 0, "y2": 0, "y3": 0, "y4": 0   # Binary decision variables
    }

# Objective function
def objective(solution):
    return sum(solution[f"x{i+1}"] * PROFITS[i] for i in range(4))

# Constraint violations with penalty
def constraint_violation(solution):
    violations = 0

    # Resource constraints
    plastic_used = sum(solution[f"x{i+1}"] * PLASTIC_USAGE[i] for i in range(4))
    if plastic_used > PLASTIC_LIMIT:
        violations += plastic_used - PLASTIC_LIMIT

    electronics_used = sum(solution[f"x{i+1}"] * ELECTRONICS_USAGE[i] for i in range(4))
    if electronics_used > ELECTRONICS_LIMIT:
        violations += electronics_used - ELECTRONICS_LIMIT

    # Logical constraints
    if solution["y1"] + solution["y4"] > 1:
        violations += 1  # Robots and dolls cannot be manufactured together
    if solution["y2"] == 1 and solution["y3"] != 1:
        violations += 1  # Model cars imply building blocks
    if solution["x4"] > solution["x2"]:
        violations += 1  # Dolls <= Model Cars

    # Linking binary and integer variables
    for i in range(1, 5):
        if solution[f"x{i}"] > M * solution[f"y{i}"]:
            violations += solution[f"x{i}"] - M * solution[f"y{i}"]

    # Non-negativity
    for i in range(1, 5):
        if solution[f"x{i}"] < 0:
            violations += abs(solution[f"x{i}"])

    return violations

# Low-level heuristics
def greedy_construction(solution):
    """Construct a solution greedily based on profit-to-resource ratio."""
    ratios = [PROFITS[i] / (PLASTIC_USAGE[i] + ELECTRONICS_USAGE[i]) for i in range(4)]
    sorted_indices = np.argsort(ratios)[::-1]
    for i in sorted_indices:
        max_count = min(
            PLASTIC_LIMIT // PLASTIC_USAGE[i],
            ELECTRONICS_LIMIT // ELECTRONICS_USAGE[i]
        )
        solution[f"x{i+1}"] = random.randint(0, max_count)
        solution[f"y{i+1}"] = 1 if solution[f"x{i+1}"] > 0 else 0
    return solution

def local_search_swap(solution):
    """Perform a local search by swapping units between two variables."""
    var1, var2 = random.sample(range(1, 5), 2)
    if solution[f"x{var1}"] > 0:
        solution[f"x{var1}"] -= 1
        solution[f"x{var2}"] += 1
        solution[f"y{var1}"] = 1 if solution[f"x{var1}"] > 0 else 0
        solution[f"y{var2}"] = 1 if solution[f"x{var2}"] > 0 else 0
    return solution

def perturbation(solution):
    """Introduce a random perturbation to the solution."""
    for i in range(1, 5):
        if random.random() < 0.5:
            solution[f"x{i}"] = max(0, solution[f"x{i}"] + random.randint(-3, 3))
            solution[f"y{i}"] = 1 if solution[f"x{i}"] > 0 else 0
    return solution

def repair_operator(solution):
    """Repair the solution to meet constraints."""
    while constraint_violation(solution) > 0:
        for i in range(1, 5):
            if solution[f"x{i}"] > 0:
                solution[f"x{i}"] -= 1
                solution[f"y{i}"] = 1 if solution[f"x{i}"] > 0 else 0
                if constraint_violation(solution) == 0:
                    break
    return solution

# Hyper-heuristic selection mechanism: reinforcement learning style
def select_operator(operators, rewards):
    probabilities = np.array(rewards) / sum(rewards)
    return np.random.choice(len(operators), p=probabilities)

# Main optimization loop
def hyper_heuristic_solver(max_iterations=1000):
    operators = [greedy_construction, local_search_swap, perturbation, repair_operator]
    rewards = [1] * len(operators)  # Initial uniform rewards
    best_solution = initialize_solution()
    best_objective = -float('inf')

    for _ in range(max_iterations):
        # Select an operator based on rewards
        operator_index = select_operator(operators, rewards)
        operator = operators[operator_index]

        # Apply the operator
        current_solution = operator(best_solution.copy())
        current_solution = repair_operator(current_solution)

        # Evaluate the solution
        current_objective = objective(current_solution)
        if constraint_violation(current_solution) == 0 and current_objective > best_objective:
            best_solution = current_solution
            best_objective = current_objective
            rewards[operator_index] += 1  # Reward the selected operator
        else:
            rewards[operator_index] = max(1, rewards[operator_index] - 1)  # Penalize

    return best_solution, best_objective

# Run the solver
if __name__ == "__main__":
    best_solution, best_objective = hyper_heuristic_solver(max_iterations=10000)
    print(f"OBJECTIVE_VALUE: {best_objective}")

