import numpy as np
import random

# Problem parameters
processing_times = {
    'A1': {'I': 5, 'II': 10, 'III': 0},
    'A2': {'I': 7, 'II': 9, 'III': 12},
    'B1': {'I': 6, 'II': 8, 'III': 0},
    'B2': {'I': 4, 'II': 0, 'III': 11},
    'B3': {'I': 7, 'II': 0, 'III': 0}
}
effective_hours = {'A1': 6000, 'A2': 10000, 'B1': 4000, 'B2': 7000, 'B3': 4000}
operating_costs = {'A1': 300, 'A2': 321, 'B1': 250, 'B2': 783, 'B3': 200}
raw_material_costs = {'I': 0.25, 'II': 0.35, 'III': 0.50}
unit_prices = {'I': 1.25, 'II': 2.00, 'III': 2.80}

# Decision variables initialization (keyed by machine and product)
decision_variables = {
    'A1': {'I': 0, 'II': 0, 'III': 0},
    'A2': {'I': 0, 'II': 0, 'III': 0},
    'B1': {'I': 0, 'II': 0, 'III': 0},
    'B2': {'I': 0, 'II': 0, 'III': 0},
    'B3': {'I': 0, 'II': 0, 'III': 0}
}

# Hyper-heuristic parameters
num_iterations = 1000
alpha = 0.1  # Learning rate for reinforcement learning
num_operators = 4
operator_weights = [1.0] * num_operators

# Constraint violation penalty multiplier
penalty_multiplier = 10000

# Helper functions for calculations
def evaluate_solution(solution):
    """Evaluate the objective value (profit) of the current solution."""
    profit = 0
    total_penalty = 0
    machine_usage = {machine: 0 for machine in effective_hours}

    # Calculate revenue and machine usage
    for machine, products in solution.items():
        for product, units in products.items():
            if units > 0:
                # Revenue and raw material cost
                profit += units * (unit_prices[product] - raw_material_costs[product])
                # Machine usage
                machine_usage[machine] += units * processing_times[machine][product]

    # Calculate operating costs
    for machine, usage in machine_usage.items():
        if usage > effective_hours[machine]:
            # Add penalty for constraint violation
            total_penalty += penalty_multiplier * (usage - effective_hours[machine])
        if usage > 0:  # Only calculate operating costs if the machine is used
            profit -= (usage / effective_hours[machine]) * operating_costs[machine]

    return profit - total_penalty

def greedy_construction():
    """Greedy construction heuristic to initialize a solution."""
    solution = {machine: {product: 0 for product in products} for machine, products in processing_times.items()}
    for product in ['I', 'II', 'III']:
        for machine in processing_times:
            if processing_times[machine][product] > 0:
                # Apply constraints for Product II and III
                if product == 'II' and machine != 'B1':
                    continue
                if product == 'III' and machine not in ['A2', 'B2']:
                    continue
                max_units = effective_hours[machine] // processing_times[machine][product]
                solution[machine][product] += max_units
                break
    return solution

def local_search_swap(solution):
    """Local search: make small changes to improve the solution."""
    machine = random.choice(list(solution.keys()))
    product = random.choice(list(solution[machine].keys()))
    if solution[machine][product] > 0:
        solution[machine][product] -= 1
    else:
        solution[machine][product] += 1
    return solution

def perturbation(solution):
    """Introduce a random change to the solution."""
    machine = random.choice(list(solution.keys()))
    product = random.choice(list(solution[machine].keys()))
    solution[machine][product] += random.randint(-10, 10)
    solution[machine][product] = max(0, solution[machine][product])
    return solution

def repair_operator(solution):
    """Repair operator to fix constraint violations."""
    machine_usage = {machine: 0 for machine in effective_hours}
    for machine, products in solution.items():
        for product, units in products.items():
            if units > 0:
                machine_usage[machine] += units * processing_times[machine][product]

    for machine, usage in machine_usage.items():
        if usage > effective_hours[machine]:
            # Reduce production to satisfy constraint
            overuse = usage - effective_hours[machine]
            for product in solution[machine]:
                reduction = min(overuse // processing_times[machine][product], solution[machine][product])
                solution[machine][product] -= reduction
                overuse -= reduction * processing_times[machine][product]
                if overuse <= 0:
                    break
    return solution

# Adaptive hyper-heuristic strategy
def select_operator():
    """Select an operator based on weighted probabilities."""
    total_weight = sum(operator_weights)
    probabilities = [w / total_weight for w in operator_weights]
    return np.random.choice(range(num_operators), p=probabilities)

# Main optimization loop
def hyper_heuristic_optimization():
    global operator_weights
    current_solution = greedy_construction()
    best_solution = current_solution
    best_objective = evaluate_solution(best_solution)

    for iteration in range(num_iterations):
        operator_idx = select_operator()

        if operator_idx == 0:
            new_solution = greedy_construction()
        elif operator_idx == 1:
            new_solution = local_search_swap(current_solution.copy())
        elif operator_idx == 2:
            new_solution = perturbation(current_solution.copy())
        elif operator_idx == 3:
            new_solution = repair_operator(current_solution.copy())

        new_objective = evaluate_solution(new_solution)
        current_objective = evaluate_solution(current_solution)

        if new_objective > current_objective:
            operator_weights[operator_idx] += alpha * (new_objective - current_objective)
            current_solution = new_solution
            if new_objective > best_objective:
                best_solution = new_solution
                best_objective = new_objective
        else:
            operator_weights[operator_idx] -= alpha * abs(new_objective - current_objective)
            operator_weights[operator_idx] = max(operator_weights[operator_idx], 0.1)  # Prevent negative weights

    return best_solution, best_objective

# Run the hyper-heuristic optimization
best_solution, best_objective = hyper_heuristic_optimization()

# Return the result
print(f"OBJECTIVE_VALUE: {best_objective}")

import numpy as np
import random

# Genetic Algorithm for solving the personnel allocation problem
# This algorithm is chosen because it is well-suited for combinatorial optimization problems
# with multiple constraints and a large search space.

# Problem data
demand = {
    (1, "Donghai"): 1000,
    (2, "Donghai"): 2000,
    (3, "Donghai"): 1500,
    (1, "Nanjiang"): 2000,
    (2, "Nanjiang"): 1000,
    (3, "Nanjiang"): 1000,
}

personnel = {
    1: {"count": 1500, "suitable": [1, 2], "preferred_specialty": 1, "preferred_city": "Donghai"},
    2: {"count": 1500, "suitable": [2, 3], "preferred_specialty": 2, "preferred_city": "Donghai"},
    3: {"count": 1500, "suitable": [1, 3], "preferred_specialty": 1, "preferred_city": "Nanjiang"},
    4: {"count": 1500, "suitable": [1, 3], "preferred_specialty": 3, "preferred_city": "Nanjiang"},
    5: {"count": 1500, "suitable": [2, 3], "preferred_specialty": 3, "preferred_city": "Donghai"},
    6: {"count": 1500, "suitable": [3], "preferred_specialty": 3, "preferred_city": "Nanjiang"},
}

# Priority Goals
P1_fulfilled = sum(demand.values())  # Total demand across all cities and specialties
P2_target = 8000  # Target number of people meeting preferred specialty
P3_target = 8000  # Target number of people meeting preferred city

# Genetic Algorithm Parameters
population_size = 50
generations = 100
mutation_rate = 0.1

# Initialize random population
def initialize_population():
    population = []
    for _ in range(population_size):
        individual = {}
        for i in personnel:
            individual[i] = {}
            total_assigned_type = 0
            for j in personnel[i]["suitable"]:
                for k in ["Donghai", "Nanjiang"]:
                    if len(personnel[i]["suitable"]) > 0:
                        max_assignable = min(personnel[i]["count"] - total_assigned_type, demand.get((j, k), 0))
                        count = random.randint(0, max_assignable)
                        individual[i][(j, k)] = count
                        total_assigned_type += count
            # Ensure the total assigned does not exceed the available count
            if total_assigned_type > personnel[i]["count"]:
                for (j, k) in individual[i]:
                    individual[i][(j, k)] = 0  # Reset assignments if over-allocated
        population.append(individual)
    return population

# Fitness function
def fitness(individual):
    total_assigned = {key: 0 for key in demand}
    preferred_specialty_count = 0
    preferred_city_count = 0
    total_penalty = 0

    for i in personnel:
        total_assigned_type = 0
        for (j, k), count in individual[i].items():
            total_assigned_type += count
            if j == personnel[i]["preferred_specialty"]:
                preferred_specialty_count += count
            if k == personnel[i]["preferred_city"]:
                preferred_city_count += count
            total_assigned[(j, k)] += count
        # Penalize if total assigned exceeds available personnel
        if total_assigned_type > personnel[i]["count"]:
            total_penalty += (total_assigned_type - personnel[i]["count"]) * 1000

    # Penalize if demand is not met
    for (j, k), required in demand.items():
        if total_assigned[(j, k)] < required:
            total_penalty += (required - total_assigned[(j, k)]) * 1000

    # Objective: Minimize the number of people who cannot meet their preferred city
    unmet_P3 = max(0, sum(personnel[i]["count"] for i in personnel) - preferred_city_count - P3_target)

    # Priority handling with penalties
    priority_penalty = total_penalty + max(0, P1_fulfilled - sum(total_assigned.values())) * 100000
    priority_penalty += max(0, P2_target - preferred_specialty_count) * 1000

    return unmet_P3 + priority_penalty

# Selection (tournament)
def selection(population):
    selected = random.sample(population, 2)
    return min(selected, key=fitness)

# Crossover
def crossover(parent1, parent2):
    child = {}
    for i in personnel:
        child[i] = {}
        for (j, k) in [(x, y) for x in range(1, 4) for y in ["Donghai", "Nanjiang"]]:
            if (j, k) in parent1[i] and (j, k) in parent2[i]:
                child[i][(j, k)] = parent1[i][(j, k)] if random.random() < 0.5 else parent2[i][(j, k)]
            else:
                child[i][(j, k)] = 0
    return child

# Mutation
def mutate(individual):
    for i in personnel:
        if random.random() < mutation_rate:
            j, k = random.choice(list(individual[i].keys()))
            if len(personnel[i]["suitable"]) > 0:
                max_assignable = min(personnel[i]["count"], demand.get((j, k), 0))
                individual[i][(j, k)] = random.randint(0, max_assignable)

# Main Genetic Algorithm
def genetic_algorithm():
    population = initialize_population()
    for generation in range(generations):
        new_population = []
        for _ in range(population_size):
            parent1 = selection(population)
            parent2 = selection(population)
            child = crossover(parent1, parent2)
            mutate(child)
            new_population.append(child)
        population = new_population

    # Get the best solution
    best_individual = min(population, key=fitness)
    return fitness(best_individual)

# Run the algorithm
best_fitness = genetic_algorithm()
print(f"OBJECTIVE_VALUE: {best_fitness}")

import numpy as np
import random

# Problem parameters
MAX_WEIGHT = 60
MIN_WEIGHT = 18
MIN_D_PER_CONTAINER = 12

WEIGHTS = {'A': 0.5, 'B': 1.0, 'C': 0.4, 'D': 0.6, 'E': 0.65}
DEMAND = {'A': 120, 'B': 90, 'C': 300, 'D': 90, 'E': 120}

# Initialize containers and solutions
NUM_CONTAINERS = 10  # Initial guess for the maximum number of containers
goods = list(WEIGHTS.keys())

def initialize_state():
    """Initialize containers with empty goods."""
    return [{'A': 0, 'B': 0, 'C': 0, 'D': 0, 'E': 0} for _ in range(NUM_CONTAINERS)]

state = initialize_state()

# Hyper-heuristic: performance-based roulette wheel selection
operator_weights = [1.0, 1.0, 1.0, 1.0]
operators = ["greedy_fill", "local_search_swap", "perturbation", "repair"]

def evaluate_solution(state):
    """Calculate the objective value and penalties of a solution."""
    total_containers_used = sum(1 for container in state if sum(container.values()) > 0)
    total_penalty = 0

    # Check each constraint
    total_goods = {g: sum(container[g] for container in state) for g in goods}
    for g in goods:
        if total_goods[g] != DEMAND[g]:
            total_penalty += abs(total_goods[g] - DEMAND[g]) * 1000

    for container in state:
        weight = sum(container[g] * WEIGHTS[g] for g in goods)
        if weight > MAX_WEIGHT:
            total_penalty += (weight - MAX_WEIGHT) * 1000
        if weight > 0 and weight < MIN_WEIGHT:  # Apply minimum weight constraint only if container is used
            total_penalty += (MIN_WEIGHT - weight) * 1000
        if weight > 0 and container['D'] < MIN_D_PER_CONTAINER:  # Enforce minimum D constraint for used containers
            total_penalty += (MIN_D_PER_CONTAINER - container['D']) * 1000
        if container['A'] > 0 and container['C'] < container['A']:  # Enforce C >= A when A > 0
            total_penalty += (container['A'] - container['C']) * 1000

    return total_containers_used, total_penalty

def greedy_fill(state):
    """Greedy filling: fill containers with goods while respecting constraints."""
    remaining = DEMAND.copy()
    for container in state:
        if sum(container.values()) > 0:
            continue
        for good in goods:
            while remaining[good] > 0:
                weight = sum(container[g] * WEIGHTS[g] for g in goods)
                if weight + WEIGHTS[good] > MAX_WEIGHT:
                    break
                container[good] += 1
                remaining[good] -= 1
                if good == 'A':  # Enforce A -> C constraint
                    if remaining['C'] > 0:
                        container['C'] += 1
                        remaining['C'] -= 1
                if sum(remaining.values()) == 0:
                    break
        # Ensure minimum D constraint
        if sum(container.values()) > 0 and container['D'] < MIN_D_PER_CONTAINER:
            deficit = MIN_D_PER_CONTAINER - container['D']
            if remaining['D'] >= deficit:
                container['D'] += deficit
                remaining['D'] -= deficit
        # Ensure minimum weight constraint
        weight = sum(container[g] * WEIGHTS[g] for g in goods)
        if weight > 0 and weight < MIN_WEIGHT:
            for good in goods:
                if remaining[good] > 0:
                    additional_units = int((MIN_WEIGHT - weight) / WEIGHTS[good])
                    additional_units = min(additional_units, remaining[good])
                    container[good] += additional_units
                    remaining[good] -= additional_units
                    weight = sum(container[g] * WEIGHTS[g] for g in goods)
                    if weight >= MIN_WEIGHT:
                        break
        if sum(remaining.values()) == 0:
            break
    return state

def local_search_swap(state):
    """Swap goods between two containers to improve the solution."""
    for _ in range(10):  # Try 10 random swaps
        i, j = random.sample(range(len(state)), 2)
        g = random.choice(goods)
        if state[i][g] > 0 and state[j][g] < DEMAND[g]:
            amount = random.randint(1, state[i][g])
            state[i][g] -= amount
            state[j][g] += amount
    return state

def perturbation(state):
    """Randomly perturb the solution."""
    for _ in range(5):  # Apply 5 random perturbations
        i = random.randint(0, len(state) - 1)
        g = random.choice(goods)
        if state[i][g] > 0:
            state[i][g] -= 1
        if state[i][g] < DEMAND[g]:
            state[i][g] += 1
    return state

def repair(state):
    """Repair solution to satisfy constraints."""
    total_goods = {g: sum(container[g] for container in state) for g in goods}
    for g in goods:
        if total_goods[g] < DEMAND[g]:
            deficit = DEMAND[g] - total_goods[g]
            for container in state:
                if sum(container.values()) == 0:
                    load = min(deficit, int(MAX_WEIGHT / WEIGHTS[g]))
                    container[g] += load
                    deficit -= load
                    if deficit == 0:
                        break
    return state

def roulette_wheel_selection(weights):
    """Select an operator index based on roulette wheel selection."""
    total_weight = sum(weights)
    pick = random.uniform(0, total_weight)
    current = 0
    for i, weight in enumerate(weights):
        current += weight
        if current > pick:
            return i

# Hyper-heuristic main loop
best_state = None
best_objective = float('inf')
best_penalty = float('inf')
iterations = 1000

for _ in range(iterations):
    state = initialize_state()  # Reset state for each iteration
    operator_idx = roulette_wheel_selection(operator_weights)
    operator = operators[operator_idx]
    new_state = globals()[operator](state)
    new_objective, new_penalty = evaluate_solution(new_state)

    if new_penalty == 0 and new_objective < best_objective:
        best_state = [container.copy() for container in new_state]
        best_objective = new_objective
        best_penalty = new_penalty

    # Update operator weights based on performance
