import numpy as np

# Cost of taking each child
costs = {
    "Harry": 1200,
    "Hermione": 1650,
    "Ron": 750,
    "Fred": 800,
    "George": 800,
    "Ginny": 1500,
}

# Constraints
mandatory_children = {"Ginny"}  # Ginny must be taken
max_children = 4  # At most 4 children can be taken
min_children = 3  # At least 3 children must be taken

# Compatibility rules
incompatibilities = [
    ("Harry", "Fred"),   # Harry cannot go with Fred
    ("Harry", "George"), # Harry cannot go with George
]
dependencies = [
    ("George", "Fred"),    # If George goes, Fred must go
    ("George", "Hermione") # If George goes, Hermione must go
]

# Heuristic: Greedy selection based on cost
def greedy_solver(costs, mandatory_children, max_children, min_children, incompatibilities, dependencies):
    # Start with mandatory children
    selected = {child: 1 for child in mandatory_children}

    # Remaining children to consider
    remaining_children = sorted(
        (child for child in costs if child not in selected),
        key=lambda c: costs[c]  # Sort by cost (ascending)
    )

    # Add children greedily while respecting constraints
    for child in remaining_children:
        if len(selected) >= max_children:
            break  # Stop if we've reached the maximum number of children

        # Check incompatibility constraints
        if any(selected.get(other, 0) == 1 for other in [x[1] for x in incompatibilities if x[0] == child]):
            continue

        # Check dependency constraints
        dependencies_met = True
        for dependency in dependencies:
            if dependency[0] == child:
                if dependency[1] not in selected:
                    # Automatically add the dependent child if not already selected
                    if len(selected) < max_children:
                        selected[dependency[1]] = 1
                    else:
                        dependencies_met = False
                        break
        if not dependencies_met:
            continue

        # Add child
        selected[child] = 1

    # Ensure at least min_children are taken
    if len(selected) < min_children:
        additional_needed = min_children - len(selected)
        for child in remaining_children:
            if child not in selected:
                # Check incompatibility constraints
                if any(selected.get(other, 0) == 1 for other in [x[1] for x in incompatibilities if x[0] == child]):
                    continue

                # Check dependency constraints
                dependencies_met = True
                for dependency in dependencies:
                    if dependency[0] == child:
                        if dependency[1] not in selected:
                            # Automatically add the dependent child if not already selected
                            if len(selected) < max_children:
                                selected[dependency[1]] = 1
                            else:
                                dependencies_met = False
                                break
                if not dependencies_met:
                    continue

                # Add child
                selected[child] = 1
                additional_needed -= 1
                if additional_needed == 0:
                    break

    # Compute the total cost
    total_cost = sum(costs[child] for child, taken in selected.items() if taken == 1)
    return total_cost

# Solve the problem
objective_value = greedy_solver(costs, mandatory_children, max_children, min_children, incompatibilities, dependencies)

# Output the result
print(f"OBJECTIVE_VALUE: {objective_value}")

import numpy as np
import random

# Problem data
costs = {
    "Harry": 1200,
    "Hermione": 1650,
    "Ron": 750,
    "Fred": 800,
    "George": 800,
    "Ginny": 1500,
}
children = list(costs.keys())

# Problem constraints and parameters
max_children = 4
min_children = 3
required = {"Ginny"}
incompatibilities = [("Harry", "Fred"), ("Harry", "George")]
implications = [("George", "Fred"), ("George", "Hermione")]

# Penalty weights
penalty_weight = 10000

# Helper functions
def evaluate_solution(solution):
    """Evaluate the solution by calculating the total cost and penalty."""
    total_cost = sum(costs[child] for child in solution if solution[child])
    penalty = 0

    # Constraint: Ginny must be taken
    if not solution["Ginny"]:
        penalty += penalty_weight

    # Constraint: Take at most max_children children
    if sum(solution.values()) > max_children:
        penalty += penalty_weight * (sum(solution.values()) - max_children)

    # Constraint: Take at least min_children children
    if sum(solution.values()) < min_children:
        penalty += penalty_weight * (min_children - sum(solution.values()))

    # Constraint: Incompatibilities
    for a, b in incompatibilities:
        if solution[a] and solution[b]:
            penalty += penalty_weight

    # Constraint: Implications
    for a, b in implications:
        if solution[a] and not solution[b]:
            penalty += penalty_weight

    # Additional constraints for George
    if solution["George"] and not solution["Fred"]:
        penalty += penalty_weight
    if solution["George"] and not solution["Hermione"]:
        penalty += penalty_weight

    return total_cost + penalty

def random_solution():
    """Generate a random feasible solution."""
    solution = {child: False for child in children}
    solution["Ginny"] = True  # Ginny must be taken

    while sum(solution.values()) < min_children:
        candidate = random.choice(children)
        if candidate not in required and not solution[candidate]:
            solution[candidate] = True
        # Ensure constraints are respected
        if any(solution[a] and solution[b] for a, b in incompatibilities):
            solution[candidate] = False
        for a, b in implications:
            if solution[a] and not solution[b]:
                solution[candidate] = False

    return solution

def greedy_construction():
    """Construct a solution greedily based on lowest cost."""
    solution = {child: False for child in children}
    solution["Ginny"] = True  # Ginny must be taken
    sorted_children = sorted(costs.keys(), key=lambda c: costs[c])

    for child in sorted_children:
        if sum(solution.values()) >= max_children:
            break
        if not solution[child] and child not in required:
            solution[child] = True
            if any(solution[a] and solution[b] for a, b in incompatibilities):
                solution[child] = False
            for a, b in implications:
                if solution[a] and not solution[b]:
                    solution[child] = False

    return solution

def local_search_swap(solution):
    """Perform a local search by swapping a random child."""
    current_cost = evaluate_solution(solution)
    new_solution = solution.copy()
    selected_child = random.choice(children)
    new_solution[selected_child] = not new_solution[selected_child]

    # Repair constraints
    if any(new_solution[a] and new_solution[b] for a, b in incompatibilities):
        new_solution[selected_child] = solution[selected_child]
    for a, b in implications:
        if new_solution[a] and not new_solution[b]:
            new_solution[selected_child] = solution[selected_child]

    if evaluate_solution(new_solution) < current_cost:
        return new_solution
    return solution

def perturbation(solution):
    """Introduce random noise to the solution."""
    new_solution = solution.copy()
    for _ in range(random.randint(1, 2)):
        child = random.choice(children)
        new_solution[child] = not new_solution[child]
        # Repair constraints
        if any(new_solution[a] and new_solution[b] for a, b in incompatibilities):
            new_solution[child] = solution[child]
        for a, b in implications:
            if new_solution[a] and not new_solution[b]:
                new_solution[child] = solution[child]
    return new_solution

def crossover_based_repair(sol1, sol2):
    """Generate a new solution by combining two parent solutions."""
    new_solution = {}
    for child in children:
        new_solution[child] = random.choice([sol1[child], sol2[child]])

    # Repair constraints
    new_solution["Ginny"] = True  # Ginny must be taken
    for a, b in implications:
        if new_solution[a]:
            new_solution[b] = True
    for a, b in incompatibilities:
        if new_solution[a] and new_solution[b]:
            new_solution[random.choice([a, b])] = False

    # Ensure minimum number of children is satisfied
    while sum(new_solution.values()) < min_children:
        candidate = random.choice(children)
        if not new_solution[candidate]:
            new_solution[candidate] = True

    return new_solution

# Hyper-heuristic: Roulette-wheel selection with performance-based weights
def hyper_heuristic(iterations=10000):
    operators = [greedy_construction, local_search_swap, perturbation, crossover_based_repair]
    weights = np.ones(len(operators))
    best_solution = random_solution()
    best_score = evaluate_solution(best_solution)

    for _ in range(iterations):
        # Select an operator using roulette-wheel selection
        operator_index = np.random.choice(len(operators), p=weights / weights.sum())
        operator = operators[operator_index]

        # Apply the operator
        if operator == crossover_based_repair:
            # If crossover, select another solution
            parent2 = random_solution()
            new_solution = operator(best_solution, parent2)
        elif operator == greedy_construction:
            new_solution = operator()  # Call without arguments
        else:
            new_solution = operator(best_solution)

        # Evaluate the new solution
        new_score = evaluate_solution(new_solution)

        # Update the best solution if improvement is found
        if new_score < best_score:
            best_solution = new_solution
            best_score = new_score
            weights[operator_index] += 1  # Reward the operator
        else:
            weights[operator_index] = max(1, weights[operator_index] - 0.1)  # Slightly penalize operator

    return best_solution, best_score

# Main execution
if __name__ == "__main__":
    best_solution, best_score = hyper_heuristic(iterations=10000)
    print(f"OBJECTIVE_VALUE: {best_score}")

import numpy as np

# Problem data
rental_fees = {
    1: 4000,  # Rental fee per 100㎡ for 1-month contracts
    2: 7500,  # Rental fee per 100㎡ for 2-month contracts
    3: 10500, # Rental fee per 100㎡ for 3-month contracts
    4: 13000  # Rental fee per 100㎡ for 4-month contracts
}
monthly_demand = [1500, 1000, 2000, 1200]  # Demand per month in ㎡

# Heuristic strategy:
# 1. Sort contract types by cost per 100㎡ per month (ascending).
# 2. Use larger contracts to cover as much demand as possible while respecting constraints.
# 3. Ensure at least two different contract lengths are used.
# 4. Limit the number of distinct contract types to at most 3.
# 5. Ensure mutual exclusion between 1-month and 4-month contracts.

def greedy_warehouse_rental(rental_fees, monthly_demand):
    # Calculate cost per 100㎡ per month for each contract
    cost_per_unit_area = {k: rental_fees[k] / k for k in rental_fees.keys()}
    sorted_contracts = sorted(cost_per_unit_area.keys(), key=lambda k: cost_per_unit_area[k])

    # Initialize variables
    contract_counts = {k: 0 for k in rental_fees.keys()}  # Number of contracts of each type
    total_area_covered = [0] * len(monthly_demand)       # Area covered for each month
    distinct_contracts_used = set()
    total_cost = 0
    tolerance = 1e-6  # Tolerance for floating-point comparisons

    # Helper function to check if adding a contract violates constraints
    def violates_constraints(contract_type):
        # Ensure mutual exclusion between 1-month and 4-month contracts
        if contract_type == 1 and 4 in distinct_contracts_used:
            return True
        if contract_type == 4 and 1 in distinct_contracts_used:
            return True
        # Limit the number of distinct contract types to at most 3
        if len(distinct_contracts_used.union({contract_type})) > 3:
            return True
        return False

    # Greedy approach: prioritize contracts with lowest cost per unit area
    for contract_type in sorted_contracts:
        for start_month in range(len(monthly_demand) - contract_type + 1):
            while True:
                # Determine the area covered by this contract
                months_covered = list(range(start_month, start_month + contract_type))  # Months covered by the contract
                contract_area = 100  # Area covered per contract

                # Check if adding another contract violates constraints
                if violates_constraints(contract_type):
                    break

                # Check if adding this contract satisfies demand
                can_satisfy = True
                for month in months_covered:
                    if total_area_covered[month] + contract_area > monthly_demand[month] + tolerance:
                        can_satisfy = False
                        break

                # Stop if the contract cannot further satisfy demand
                if not can_satisfy:
                    break

                # Add this contract
                contract_counts[contract_type] += 1
                total_cost += rental_fees[contract_type] * (contract_area / 100)
                distinct_contracts_used.add(contract_type)
                for month in months_covered:
                    total_area_covered[month] += contract_area

    # Ensure all monthly demands are satisfied
    for i, demand in enumerate(monthly_demand):
        if total_area_covered[i] < demand - tolerance:
            # If demand is not satisfied, try to allocate additional contracts
            remaining_demand = demand - total_area_covered[i]
            for contract_type in sorted_contracts:
                if violates_constraints(contract_type):
                    continue
                while remaining_demand > 0:
                    months_covered = list(range(i, min(i + contract_type, len(monthly_demand))))
                    contract_area = 100
                    can_satisfy = True
                    for month in months_covered:
                        if total_area_covered[month] + contract_area > monthly_demand[month] + tolerance:
                            can_satisfy = False
                            break
                    if not can_satisfy:
                        break
                    # Add this contract
                    contract_counts[contract_type] += 1
                    total_cost += rental_fees[contract_type] * (contract_area / 100)
                    distinct_contracts_used.add(contract_type)
                    for month in months_covered:
                        total_area_covered[month] += contract_area
                        remaining_demand -= contract_area
                    if remaining_demand <= 0:
                        break
            if total_area_covered[i] < demand - tolerance:
                raise ValueError("Failed to satisfy the demand in month {}".format(i + 1))

    # Ensure at least two distinct contract lengths were used
    if len(distinct_contracts_used) < 2:
        raise ValueError("Failed to use at least two distinct contract lengths")

    # Ensure mutual exclusion between 1-month and 4-month contracts
    if 1 in distinct_contracts_used and 4 in distinct_contracts_used:
        raise ValueError("Mutual exclusion violated between 1-month and 4-month contracts")

    # Ensure the number of distinct contract types does not exceed 3
    if len(distinct_contracts_used) > 3:
        raise ValueError("Exceeded the limit of 3 distinct contract types")

    return total_cost

# Solve the problem
try:
    objective_value = greedy_warehouse_rental(rental_fees, monthly_demand)
    print(f"OBJECTIVE_VALUE: {objective_value}")
except ValueError as e:
    print(f"Error: {e}")

