# Improved heuristic: Select courses for each category to minimize total courses
def optimized_minimum_courses(categories, prerequisites):
    selected_courses = set()
    remaining_courses = set(course for category in categories.values() for course in category)

    # Sort courses by how many categories they fulfill (higher is better)
    course_priority = {course: get_course_priority(course, categories) for course in remaining_courses}
    sorted_courses = sorted(course_priority.keys(), key=lambda c: -course_priority[c])

    # Select courses while ensuring prerequisites and category constraints are met
    while True:
        # Check if all category constraints are satisfied
        if all(len([c for c in selected_courses if c in categories[cat]]) >= 2 for cat in categories):
            # Check if prerequisites are satisfied
            if check_prerequisites(selected_courses):
                break

        # Select the next best course
        for course in sorted_courses:
            if course not in selected_courses:
                # Temporarily add the course and its prerequisites
                temp_selected = selected_courses | {course}
                for prereq in prerequisites.get(course, []):
                    temp_selected.add(prereq)

                # Check if adding this course satisfies prerequisites
                if check_prerequisites(temp_selected):
                    selected_courses = temp_selected
                    break

    return selected_courses

