import numpy as np
import random

# Problem constants
NUM_COURSES = 7
COURSES = ["x_Calculus", "x_OperationsResearch", "x_DataStructures", 
           "x_ManagementStatistics", "x_ComputerSimulation", 
           "x_ComputerProgramming", "x_Forecasting"]

# Categories and prerequisites
CATEGORIES = {
    "Mathematics": [0, 1, 2, 3, 6],
    "OperationsResearch": [1, 3, 4, 6],
    "ComputerScience": [5, 2, 4]
}
PREREQUISITES = {
    4: [5],  # ComputerSimulation requires ComputerProgramming
    2: [5],  # DataStructures requires ComputerProgramming
    3: [0],  # ManagementStatistics requires Calculus
    6: [3]   # Forecasting requires ManagementStatistics
}

# Constraints
MIN_COURSES_PER_CATEGORY = 2

# Genetic Algorithm parameters
POPULATION_SIZE = 50
GENERATIONS = 100
MUTATION_RATE = 0.1
CROSSOVER_RATE = 0.8

# Fitness function
def fitness(individual):
    total_courses = sum(individual)
    penalties = 0

    # Category constraints
    for category, indices in CATEGORIES.items():
        if sum(individual[i] for i in indices) < MIN_COURSES_PER_CATEGORY:
            penalties += 1000  # Large penalty for unmet category constraint

    # Prerequisite constraints
    for course, prereqs in PREREQUISITES.items():
        if individual[course] == 1:  # If a course is taken
            for prereq in prereqs:
                if individual[prereq] == 0:  # If prerequisite is not taken
                    penalties += 1000  # Large penalty for unmet prerequisite

    return total_courses + penalties

# Generate a random individual
def random_individual():
    while True:
        individual = [random.randint(0, 1) for _ in range(NUM_COURSES)]
        if is_valid(individual):
            return individual

# Crossover operation
def crossover(parent1, parent2):
    if random.random() < CROSSOVER_RATE:
        point = random.randint(1, NUM_COURSES - 1)
        return parent1[:point] + parent2[point:]
    return parent1.copy()

# Mutation operation
def mutate(individual):
    for i in range(NUM_COURSES):
        if random.random() < MUTATION_RATE:
            individual[i] = 1 - individual[i]  # Flip bit
    if not is_valid(individual):
        individual = repair_individual(individual)
    return individual

# Selection operation (tournament selection)
def select(population, fitnesses):
    idx1, idx2 = random.sample(range(len(population)), 2)
    return population[idx1] if fitnesses[idx1] < fitnesses[idx2] else population[idx2]

# Check if an individual is valid
def is_valid(individual):
    # Check category constraints
    for category, indices in CATEGORIES.items():
        if sum(individual[i] for i in indices) < MIN_COURSES_PER_CATEGORY:
            return False
    # Check prerequisite constraints
    for course, prereqs in PREREQUISITES.items():
        if individual[course] == 1:
            for prereq in prereqs:
                if individual[prereq] == 0:
                    return False
    return True

# Repair an individual to make it valid
def repair_individual(individual):
    # Ensure category constraints
    for category, indices in CATEGORIES.items():
        while sum(individual[i] for i in indices) < MIN_COURSES_PER_CATEGORY:
            for i in indices:
                if individual[i] == 0:
                    individual[i] = 1
                    break

    # Ensure prerequisite constraints
    for course, prereqs in PREREQUISITES.items():
        if individual[course] == 1:
            for prereq in prereqs:
                individual[prereq] = 1

    return individual

# Genetic Algorithm implementation
def genetic_algorithm():
    # Initialize population
    population = [random_individual() for _ in range(POPULATION_SIZE)]
    best_individual = None
    best_fitness = float('inf')

    for generation in range(GENERATIONS):
        # Evaluate fitness for each individual
        fitnesses = [fitness(ind) for ind in population]

        # Update best solution
        for i, f in enumerate(fitnesses):
            if f < best_fitness:
                best_fitness = f
                best_individual = population[i]

        # Generate new population
        new_population = []
        for _ in range(POPULATION_SIZE // 2):
            parent1 = select(population, fitnesses)
            parent2 = select(population, fitnesses)
            offspring1 = mutate(crossover(parent1, parent2))
            offspring2 = mutate(crossover(parent1, parent2))
            new_population.extend([offspring1, offspring2])

        population = new_population

    return best_individual, best_fitness

# Run the genetic algorithm
if __name__ == "__main__":
    best_solution, best_value = genetic_algorithm()

    # Validate solution
    valid = is_valid(best_solution)

    if valid:
        print(f"OBJECTIVE_VALUE: {sum(best_solution)}")
        print(f"Selected courses: {[COURSES[i] for i in range(NUM_COURSES) if best_solution[i] == 1]}")
    else:
        print(f"OBJECTIVE_VALUE: {best_value}")
        print("No valid solution found, but the best attempt was:")
        print(f"Selected courses: {[COURSES[i] for i in range(NUM_COURSES) if best_solution[i] == 1]}")

